import React, {useState} from 'react';
import { useNavigate } from 'react-router-dom';
import api, { setToken } from '../services/api';
import './Signup.css';

export default function Login(){
  const [form, setForm] = useState({username:'', password:''});
  const [msg, setMsg] = useState(null);
  const [submitting, setSubmitting] = useState(false);
  const navigate = useNavigate();

  const onChange = e => setForm({...form, [e.target.name]: e.target.value});

  const onSubmit = async e => {
    e.preventDefault();
    setSubmitting(true);
    setMsg(null);
    try{
      const res = await api.post('/auth/login', form);
      setToken(res.data.token);
      setMsg({type:'success', text:'Logged in successfully'});
      setTimeout(() => navigate('/dashboard'), 800);
    }catch(err){
      const text = err?.response?.data?.error || 'Login failed';
      setMsg({type:'error', text});
    }finally{
      setSubmitting(false);
    }
  };

  return (
    <div className="signup-page" style={{
      backgroundImage: "linear-gradient(rgba(15, 76, 155, 0.42), rgba(15, 76, 155, 0.32)), url('/fishwallpaper.jpg')",
      backgroundSize: 'cover',
      backgroundPosition: 'center'
    }}>
      <div className="signup-card">
        <div className="signup-card__header">
          <h2>Welcome back</h2>
          <p>Sign in to your account and continue managing your fish dealership.</p>
        </div>
        <div className="signup-card__body">
          {msg && <div className={`signup-message ${msg.type}`}>{msg.text}</div>}
          <form className="signup-form" onSubmit={onSubmit}>
            <div className="field-group">
              <input
                className="field-input"
                id="username"
                name="username"
                type="text"
                value={form.username}
                onChange={onChange}
                placeholder=" "
                required
              />
              <label className="field-label" htmlFor="username">Username</label>
            </div>
            <div className="field-group">
              <input
                className="field-input"
                id="password"
                name="password"
                type="password"
                value={form.password}
                onChange={onChange}
                placeholder=" "
                required
              />
              <label className="field-label" htmlFor="password">Password</label>
            </div>
            <div className="submit-row">
              <button className="submit-btn" type="submit" disabled={submitting}>
                {submitting ? 'Signing in...' : 'Sign in'}
              </button>
            </div>
          </form>
          <div className="auth-footer">
            <span>New here?</span>
            <button className="auth-link" onClick={() => navigate('/signup')} type="button">Create account</button>
          </div>
        </div>
      </div>
    </div>
  );
}
